-- Script de criação e população da tabela de medicamentos para AtendClinical (Farmácia)

CREATE TABLE IF NOT EXISTS public.farmacia_medicamentos (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    nome TEXT NOT NULL UNIQUE,
    aliases TEXT[],
    preco NUMERIC(10, 2) NOT NULL,
    categoria TEXT NOT NULL,
    precisa_receita BOOLEAN NOT NULL DEFAULT false,
    tipo_receita TEXT, -- 'simples', 'retida', 'azul', 'especial'
    permite_delivery BOOLEAN NOT NULL DEFAULT true,
    apresentacao TEXT,
    unidade_medida TEXT,
    principio_ativo TEXT,
    indicacao TEXT,
    posologia TEXT,
    contraindicacoes TEXT,
    fabricante TEXT,
    eh_generico BOOLEAN NOT NULL DEFAULT false,
    created_at TIMESTAMPTZ DEFAULT now()
);

-- Habilitar RLS (Row Level Security)
ALTER TABLE public.farmacia_medicamentos ENABLE ROW LEVEL SECURITY;

-- Criar política de leitura pública (anon e authenticated)
DROP POLICY IF EXISTS "Permitir leitura pública de medicamentos" ON public.farmacia_medicamentos;
CREATE POLICY "Permitir leitura pública de medicamentos" 
ON public.farmacia_medicamentos 
FOR SELECT 
USING (true);

-- Limpar dados anteriores se existirem (para evitar duplicados no seed)
TRUNCATE TABLE public.farmacia_medicamentos CASCADE;

